(async () => {
  const pad = 16;   // dimension-4
  const gap = 16;   // dimension-4
  const gapSm = 8;  // dimension-2
  const gapMd = 12; // dimension-3
  const radiusCard = 16;  // radius-400
  const radiusBlock = 12; // radius-300
  const radiusLogo = 8;   // radius-200
  const logoSize = 40;    // size-9 / dimension-9
  const borderW = 1;

  function getVar(name) {
    for (const col of figma.variableCollections) {
      for (const id of col.variableIds) {
        const v = figma.variables.getVariableById(id);
        if (v && v.name === name) return v.id;
      }
    }
    return null;
  }

  const tokenIds = {
    surfaceDefault: getVar('color/light/color/surface/default') || getVar('Semantics/surface/default'),
    surfaceRaised: getVar('color/light/color/surface/raised') || getVar('Semantics/surface/raised'),
    textPrimary: getVar('color/light/color/text/primary') || getVar('Semantics/text/primary'),
    textSecondary: getVar('color/light/color/text/secondary') || getVar('Semantics/text/secondary'),
    textTertiary: getVar('color/light/color/text/tertiary') || getVar('Semantics/text/tertiary'),
    borderSubtle: getVar('color/light/color/border/subtle') || getVar('Semantics/border/subtle'),
  };

  const hexFallback = {
    surfaceDefault: { r: 252/255, g: 252/255, b: 253/255 },
    surfaceRaised: { r: 242/255, g: 244/255, b: 247/255 },
    textPrimary: { r: 28/255, g: 32/255, b: 36/255 },
    textSecondary: { r: 139/255, g: 141/255, b: 152/255 },
    textTertiary: { r: 169/255, g: 169/255, b: 169/255 },
    borderSubtle: { r: 242/255, g: 244/255, b: 247/255 },
  };

  function setFill(node, tokenKey) {
    const id = tokenIds[tokenKey];
    if (id && node.setBoundVariable) {
      try {
        node.setBoundVariable('fills', id);
        return;
      } catch (_) {}
    }
    const c = hexFallback[tokenKey];
    node.fills = [{ type: 'SOLID', color: c }];
  }

  function setStroke(node, tokenKey) {
    const id = tokenIds[tokenKey];
    if (id && node.setBoundVariable) {
      try {
        node.setBoundVariable('strokes', id);
        return;
      } catch (_) {}
    }
    const c = hexFallback[tokenKey];
    node.strokes = [{ type: 'SOLID', color: c }];
  }

  await Promise.all([
    figma.loadFontAsync({ family: 'Roboto', style: 'Regular' }),
    figma.loadFontAsync({ family: 'Roboto', style: 'Medium' }),
    figma.loadFontAsync({ family: 'Roboto', style: 'Bold' }),
  ]);

  let section = figma.currentPage.findOne(n => n.type === 'SECTION' && n.name === 'Design Components');
  if (!section) {
    section = figma.createSection();
    section.name = 'Design Components';
    section.x = 0;
    section.y = 0;
    figma.currentPage.appendChild(section);
  }

  const root = figma.createFrame();
  root.name = 'Shop/Organism/OrderSummaryCard';
  root.layoutMode = 'VERTICAL';
  root.primaryAxisSizingMode = 'AUTO';
  root.counterAxisSizingMode = 'AUTO';
  root.primaryAxisAlignItems = 'MIN';
  root.counterAxisAlignItems = 'MIN';
  root.itemSpacing = gap;
  root.paddingLeft = pad;
  root.paddingRight = pad;
  root.paddingTop = pad;
  root.paddingBottom = pad;
  root.cornerRadius = radiusCard;
  root.strokeWeight = borderW;
  setFill(root, 'surfaceDefault');
  setStroke(root, 'borderSubtle');

  const headerRow = figma.createFrame();
  headerRow.name = 'HeaderBlock';
  headerRow.layoutMode = 'HORIZONTAL';
  headerRow.primaryAxisSizingMode = 'FILL';
  headerRow.counterAxisSizingMode = 'AUTO';
  headerRow.primaryAxisAlignItems = 'SPACE_BETWEEN';
  headerRow.counterAxisAlignItems = 'CENTER';
  headerRow.itemSpacing = gapSm;
  root.appendChild(headerRow);

  const titleText = figma.createText();
  await figma.loadFontAsync({ family: 'Roboto', style: 'Medium' });
  titleText.characters = 'Resumo do seu Pedido';
  titleText.fontSize = 16;
  titleText.fontName = { family: 'Roboto', style: 'Medium' };
  if (tokenIds.textPrimary && titleText.setBoundVariable) {
    try { titleText.setBoundVariable('fills', tokenIds.textPrimary); } catch (_) {
      titleText.fills = [{ type: 'SOLID', color: hexFallback.textPrimary }];
    }
  } else {
    titleText.fills = [{ type: 'SOLID', color: hexFallback.textPrimary }];
  }
  headerRow.appendChild(titleText);

  const editLink = figma.createText();
  editLink.characters = 'Editar';
  editLink.fontSize = 14;
  editLink.fontName = { family: 'Roboto', style: 'Regular' };
  if (tokenIds.textSecondary && editLink.setBoundVariable) {
    try { editLink.setBoundVariable('fills', tokenIds.textSecondary); } catch (_) {
      editLink.fills = [{ type: 'SOLID', color: hexFallback.textSecondary }];
    }
  } else {
    editLink.fills = [{ type: 'SOLID', color: hexFallback.textSecondary }];
  }
  headerRow.appendChild(editLink);

  const itemRow = figma.createFrame();
  itemRow.name = 'ItemDetailsBlock';
  itemRow.layoutMode = 'HORIZONTAL';
  itemRow.primaryAxisSizingMode = 'FILL';
  itemRow.counterAxisSizingMode = 'AUTO';
  itemRow.primaryAxisAlignItems = 'CENTER';
  itemRow.counterAxisAlignItems = 'CENTER';
  itemRow.itemSpacing = gapMd;
  root.appendChild(itemRow);

  const logoPlaceholder = figma.createRectangle();
  logoPlaceholder.name = 'PartnerLogo';
  logoPlaceholder.resize(logoSize, logoSize);
  logoPlaceholder.cornerRadius = radiusLogo;
  setFill(logoPlaceholder, 'surfaceRaised');
  itemRow.appendChild(logoPlaceholder);

  const brandName = figma.createText();
  brandName.characters = 'Centauro';
  brandName.fontSize = 14;
  brandName.fontName = { family: 'Roboto', style: 'Regular' };
  if (tokenIds.textPrimary && brandName.setBoundVariable) {
    try { brandName.setBoundVariable('fills', tokenIds.textPrimary); } catch (_) {
      brandName.fills = [{ type: 'SOLID', color: hexFallback.textPrimary }];
    }
  } else {
    brandName.fills = [{ type: 'SOLID', color: hexFallback.textPrimary }];
  }
  itemRow.appendChild(brandName);

  const spacer = figma.createFrame();
  spacer.name = 'Spacer';
  spacer.layoutMode = 'HORIZONTAL';
  spacer.primaryAxisSizingMode = 'FILL';
  spacer.counterAxisSizingMode = 'AUTO';
  spacer.resize(1, 1);
  itemRow.appendChild(spacer);

  const itemPrice = figma.createText();
  itemPrice.characters = 'R$ 2.000,00';
  itemPrice.fontSize = 14;
  itemPrice.fontName = { family: 'Roboto', style: 'Regular' };
  if (tokenIds.textPrimary && itemPrice.setBoundVariable) {
    try { itemPrice.setBoundVariable('fills', tokenIds.textPrimary); } catch (_) {
      itemPrice.fills = [{ type: 'SOLID', color: hexFallback.textPrimary }];
    }
  } else {
    itemPrice.fills = [{ type: 'SOLID', color: hexFallback.textPrimary }];
  }
  itemRow.appendChild(itemPrice);

  const itemQty = figma.createText();
  itemQty.characters = '| 2 Gift Cards';
  itemQty.fontSize = 14;
  itemQty.fontName = { family: 'Roboto', style: 'Regular' };
  if (tokenIds.textSecondary && itemQty.setBoundVariable) {
    try { itemQty.setBoundVariable('fills', tokenIds.textSecondary); } catch (_) {
      itemQty.fills = [{ type: 'SOLID', color: hexFallback.textSecondary }];
    }
  } else {
    itemQty.fills = [{ type: 'SOLID', color: hexFallback.textSecondary }];
  }
  itemRow.appendChild(itemQty);

  const summaryBlock = figma.createFrame();
  summaryBlock.name = 'SummaryCalculationsBlock';
  summaryBlock.layoutMode = 'VERTICAL';
  summaryBlock.primaryAxisSizingMode = 'FILL';
  summaryBlock.counterAxisSizingMode = 'AUTO';
  summaryBlock.primaryAxisAlignItems = 'MIN';
  summaryBlock.counterAxisAlignItems = 'MIN';
  summaryBlock.itemSpacing = gapSm;
  summaryBlock.paddingLeft = pad;
  summaryBlock.paddingRight = pad;
  summaryBlock.paddingTop = pad;
  summaryBlock.paddingBottom = pad;
  summaryBlock.cornerRadius = radiusBlock;
  setFill(summaryBlock, 'surfaceRaised');
  root.appendChild(summaryBlock);

  function addSummaryRow(label, value, options = {}) {
    const row = figma.createFrame();
    row.name = 'SummaryRow';
    row.layoutMode = 'HORIZONTAL';
    row.primaryAxisSizingMode = 'FILL';
    row.counterAxisSizingMode = 'AUTO';
    row.primaryAxisAlignItems = 'SPACE_BETWEEN';
    row.counterAxisAlignItems = 'CENTER';
    row.itemSpacing = gapSm;
    const l = figma.createText();
    l.characters = label;
    l.fontSize = options.fontSize || 14;
    l.fontName = { family: 'Roboto', style: options.bold ? 'Bold' : 'Regular' };
    l.fills = [{ type: 'SOLID', color: (options.secondary ? hexFallback.textSecondary : (options.tertiary ? hexFallback.textTertiary : hexFallback.textPrimary)) }];
    if (options.tertiary && tokenIds.textTertiary && l.setBoundVariable) {
      try { l.setBoundVariable('fills', tokenIds.textTertiary); } catch (_) {}
    } else if (options.secondary && tokenIds.textSecondary && l.setBoundVariable) {
      try { l.setBoundVariable('fills', tokenIds.textSecondary); } catch (_) {}
    } else if (tokenIds.textPrimary && l.setBoundVariable) {
      try { l.setBoundVariable('fills', tokenIds.textPrimary); } catch (_) {}
    }
    row.appendChild(l);
    const v = figma.createText();
    v.characters = value;
    v.fontSize = options.fontSize || 14;
    v.fontName = { family: 'Roboto', style: options.bold ? 'Bold' : 'Regular' };
    v.fills = [{ type: 'SOLID', color: options.secondary ? hexFallback.textSecondary : (options.tertiary ? hexFallback.textTertiary : hexFallback.textPrimary) }];
    if (options.tertiary && tokenIds.textTertiary && v.setBoundVariable) {
      try { v.setBoundVariable('fills', tokenIds.textTertiary); } catch (_) {}
    } else if (options.secondary && tokenIds.textSecondary && v.setBoundVariable) {
      try { v.setBoundVariable('fills', tokenIds.textSecondary); } catch (_) {}
    } else if (tokenIds.textPrimary && v.setBoundVariable) {
      try { v.setBoundVariable('fills', tokenIds.textPrimary); } catch (_) {}
    }
    row.appendChild(v);
    summaryBlock.appendChild(row);
  }

  addSummaryRow('Subtotal (2 Gifts Cards)', 'R$ 2.000,00');
  addSummaryRow('Pagamento com Pix:', 'R$ 2.000,00');
  addSummaryRow('Taxa de serviço: ⓘ', 'R$ 0,00', { tertiary: true });
  addSummaryRow('Total:', 'R$ 2.000,00', { bold: true });

  section.appendChild(root);
  root.x = section.children.length === 1 ? 0 : (section.children[section.children.length - 2].x + section.children[section.children.length - 2].width + 24);
  root.y = 0;
  figma.viewport.scrollAndZoomIntoView([root]);
  figma.currentPage.selection = [root];
  return { nodeId: root.id, name: root.name };
})();
